function setupCourseDetails() {
const urlParams = new URLSearchParams(window.location.search);
const courseKey = urlParams.get("course") || "iha2";
const data = coursesData[courseKey];
if (!data) return;
const titleEl = document.getElementById("detailTitle");
const subtitleEl = document.getElementById("detailSubtitle");
const badgeEl = document.getElementById("detailCategoryBadge");
const durationEl = document.getElementById("detailDurationVal");
const certEl = document.getElementById("detailCertVal");
const blurbP1El = document.getElementById("detailBlurbP1");
const blurbP2El = document.getElementById("detailBlurbP2");
const imgEl = document.getElementById("detailHeroImg");
const breadcrumbCurrentEl = document.getElementById("detailBreadcrumbCurrent");
if (titleEl) titleEl.setAttribute("data-i18n", data.titleI18n);
if (subtitleEl) subtitleEl.setAttribute("data-i18n", data.subtitleI18n);
if (badgeEl) {
badgeEl.setAttribute("data-i18n", data.badgeI18n);
badgeEl.className = `detail-category-badge detail-category-badge-${data.category}`;
}
if (durationEl) durationEl.setAttribute("data-i18n", data.durationI18n);
if (certEl) certEl.setAttribute("data-i18n", data.certI18n);
if (blurbP1El) blurbP1El.setAttribute("data-i18n", data.blurbP1I18n);
if (blurbP2El) blurbP2El.setAttribute("data-i18n", data.blurbP2I18n);
if (imgEl) {
imgEl.src = data.img;
imgEl.alt = courseKey.toUpperCase();
}
if (breadcrumbCurrentEl) {
breadcrumbCurrentEl.setAttribute("data-i18n", `bc_${courseKey}`);
}
const reqsContainer = document.getElementById("detailRequirementsList");
if (reqsContainer) {
let reqsHtml = "";
data.reqs.forEach(reqKey => {
reqsHtml += `
<li>
<svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor">
<path d="M9 16.17L4.83 12l-1.42 1.41L9 19 21 7l-1.41-1.41z"/>
</svg>
<span data-i18n="${reqKey}"></span>
</li>
`;
});
reqsContainer.innerHTML = reqsHtml;
}
}
document.addEventListener("DOMContentLoaded", () => {
setupCourseDetails();
setupMobileMenu();
setupTheme();
setupLanguage();
setupColumnExpansion();
setupSessionsPagination(typeof sessionsData !== 'undefined' ? sessionsData : []);
});
function setupMobileMenu() {
const hamburger = document.getElementById("hamburger");
const navMenu = document.getElementById("navMenu");
const navLinks = document.querySelectorAll(".nav-link");
if (hamburger && navMenu) {
hamburger.addEventListener("click", () => {
hamburger.classList.toggle("open");
navMenu.classList.toggle("open");
});
navLinks.forEach(link => {
link.addEventListener("click", () => {
hamburger.classList.remove("open");
navMenu.classList.remove("open");
});
});
}
}
function setupTheme() {
const themeToggleBtn = document.getElementById("themeToggle");
const currentTheme = localStorage.getItem("theme");
if (currentTheme === "light") {
document.body.classList.add("light-mode");
}
if (themeToggleBtn) {
themeToggleBtn.addEventListener("click", () => {
document.body.classList.toggle("light-mode");
const theme = document.body.classList.contains("light-mode") ? "light" : "dark";
localStorage.setItem("theme", theme);
});
}
}
function setupLanguage() {
const langSelect = document.getElementById("langSelect");
let currentLang = localStorage.getItem("language") || "tr";
if (langSelect) {
langSelect.value = currentLang;
langSelect.addEventListener("change", (e) => {
const selectedLang = e.target.value;
localStorage.setItem("language", selectedLang);
updatePageLanguage(selectedLang);
document.documentElement.lang = selectedLang;
});
}
updatePageLanguage(currentLang);
}
function updatePageLanguage(lang) {
const translatableElements = document.querySelectorAll("[data-i18n]");
translatableElements.forEach(element => {
const key = element.getAttribute("data-i18n");
if (translations[key] && translations[key][lang]) {
element.textContent = translations[key][lang];
}
});
const tooltipElements = document.querySelectorAll("[data-i18n-tooltip]");
tooltipElements.forEach(element => {
const key = element.getAttribute("data-i18n-tooltip");
if (translations[key] && translations[key][lang]) {
element.setAttribute("data-tooltip", translations[key][lang]);
}
});
}
function setupColumnExpansion() {
const expandPilotaj = document.getElementById("expandPilotaj");
const expandDrone = document.getElementById("expandDrone");
const columnsContainer = document.getElementById("coursesColumns");
const pilotajCol = document.getElementById("pilotajColumn");
const droneCol = document.getElementById("droneColumn");
if (!columnsContainer || !pilotajCol || !droneCol) return;
const toggleExpand = (expandedCol, collapsedCol, btn) => {
const isExpanded = expandedCol.classList.contains("expanded");
pilotajCol.classList.remove("expanded", "collapsed");
droneCol.classList.remove("expanded", "collapsed");
columnsContainer.classList.remove("has-expanded");
document.querySelectorAll(".column-expand-btn").forEach(b => {
b.querySelector(".icon-expand").style.display = "block";
b.querySelector(".icon-collapse").style.display = "none";
});
if (!isExpanded) {
expandedCol.classList.add("expanded");
collapsedCol.classList.add("collapsed");
columnsContainer.classList.add("has-expanded");
btn.querySelector(".icon-expand").style.display = "none";
btn.querySelector(".icon-collapse").style.display = "block";
}
};
if (expandPilotaj) {
expandPilotaj.addEventListener("click", () => {
toggleExpand(pilotajCol, droneCol, expandPilotaj);
});
}
if (expandDrone) {
expandDrone.addEventListener("click", () => {
toggleExpand(droneCol, pilotajCol, expandDrone);
});
}
}
function setupSessionsPagination(sessionsArray) {
const sessionsContainer = document.querySelector(".ao3-sessions-list");
if (!sessionsContainer) return;
const today = new Date("2026-07-10");
const itemsPerPage = 5;
let currentPage = 1;
const sessions = Array.isArray(sessionsArray) ? [...sessionsArray] : [];
sessions.sort((a, b) => {
const dateA = new Date(a.startDate);
const dateB = new Date(b.startDate);
const isExpiredA = dateA - today < 0;
const isExpiredB = dateB - today < 0;
if (!isExpiredA && isExpiredB) return -1;
if (isExpiredA && !isExpiredB) return 1;
if (!isExpiredA && !isExpiredB) {
return dateA - dateB;
}
if (isExpiredA && isExpiredB) {
return dateB - dateA;
}
return 0;
});
function renderPage() {
const lang = localStorage.getItem("language") || "tr";
const totalPages = Math.ceil(sessions.length / itemsPerPage);
const startIdx = (currentPage - 1) * itemsPerPage;
const endIdx = startIdx + itemsPerPage;
const paginatedSessions = sessions.slice(startIdx, endIdx);
let html = "";
paginatedSessions.forEach(session => {
const start = new Date(session.startDate);
const diffTime = start - today;
const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
let cardState = "state-open";
let statusText = lang === "tr" ? "Başvurular Açık" : "Applications Open";
let badgeClass = "badge-success";
let signupButtonHtml = `<a href="register.html?sessionId=${session.id}" class="btn btn-primary">${lang === 'tr' ? 'Hemen Kayıt Ol' : 'Register Now'}</a>`;
if (diffDays < 0) {
cardState = "state-expired";
statusText = lang === "tr" ? "Kayıtlar Kapatıldı" : "Registrations Closed";
badgeClass = "badge-expired";
signupButtonHtml = `<button class="btn btn-secondary" disabled>${lang === 'tr' ? 'Kayıtlar Kapatıldı' : 'Registrations Closed'}</button>`;
} else if (diffDays <= 7) {
cardState = "state-selling-fast";
statusText = lang === "tr" ? "Son Başvuru Tarihi Yakın" : "Deadline Approaching";
badgeClass = "badge-warning";
}
const dateText = lang === "tr" ? session.dateTextTR : session.dateTextEN;
const classType = lang === "tr" ? session.typeTR : session.typeEN;
const timingLabel = lang === "tr" ? "Zaman Bloğu:" : "Time Block:";
const timingValue = lang === "tr" ? session.timingTR : session.timingEN;
const locationLabel = lang === "tr" ? "Eğitim Yeri:" : "Training Venue:";
const locationValue = lang === "tr" ? session.locationTR : session.locationEN;
const registeredLabel = lang === "tr" ? "Kayıtlı Öğrenci:" : "Registered Students:";
const studentsLabel = lang === "tr" ? "Öğrenci" : "Students";
const paymentLabel = lang === "tr" ? "Ödeme Detayları:" : "Payment Details:";
const paymentValue = lang === "tr" ? session.paymentTR : session.paymentEN;
const vatDetailText = lang === "tr" ? "+ KDV (%20)" : "+ VAT (20%)";
const priceText = cardState === "state-expired" ? (lang === "tr" ? "Geçmiş Dönem" : "Past Term") : vatDetailText;
const classTypeClass = session.isWeekend ? "session-class-type is-weekend-class" : "session-class-type";
html += `
<div class="session-card ${cardState}">
<div class="session-card-header">
<div class="session-main-info">
<span class="session-status-badge ${badgeClass}">${statusText}</span>
<h3 class="session-date-range">${dateText}</h3>
<span class="${classTypeClass}">${classType}</span>
</div>
<div class="session-price-block">
<span class="price-val">${session.price}</span>
<span class="price-details">${priceText}</span>
</div>
</div>
<div class="session-card-body">
<div class="session-details-grid">
<div class="detail-item">
<span class="detail-lbl">${timingLabel}</span>
<span class="detail-val">${timingValue}</span>
</div>
<div class="detail-item">
<span class="detail-lbl">${locationLabel}</span>
<span class="detail-val">${locationValue}</span>
</div>
<div class="detail-item">
<span class="detail-lbl">${registeredLabel}</span>
<span class="detail-val">${session.registeredCount} ${studentsLabel}</span>
</div>
<div class="detail-item">
<span class="detail-lbl">${paymentLabel}</span>
<span class="detail-val">${paymentValue}</span>
</div>
</div>
</div>
<div class="session-card-actions">
${signupButtonHtml}
</div>
</div>
`;
});
const prevText = lang === "tr" ? "Önceki" : "Previous";
const nextText = lang === "tr" ? "Sonraki" : "Next";
const pageInfoText = lang === "tr" ? `Sayfa ${currentPage} / ${totalPages}` : `Page ${currentPage} / ${totalPages}`;
html += `
<div class="sessions-pagination">
<button class="pagination-btn prev-btn" id="sessionsPrevBtn" ${currentPage === 1 ? "disabled" : ""}>
<svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
<path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
</svg>
<span>${prevText}</span>
</button>
<div class="pagination-info">
<span>${pageInfoText}</span>
</div>
<button class="pagination-btn next-btn" id="sessionsNextBtn" ${currentPage === totalPages ? "disabled" : ""}>
<span>${nextText}</span>
<svg viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
<path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
</svg>
</button>
</div>
`;
sessionsContainer.innerHTML = html;
document.getElementById("sessionsPrevBtn").addEventListener("click", () => {
if (currentPage > 1) {
currentPage--;
renderPage();
document.querySelector(".detail-sessions-section").scrollIntoView({ behavior: "smooth" });
}
});
document.getElementById("sessionsNextBtn").addEventListener("click", () => {
if (currentPage < totalPages) {
currentPage++;
renderPage();
document.querySelector(".detail-sessions-section").scrollIntoView({ behavior: "smooth" });
}
});
}
renderPage();
const langSelect = document.getElementById("langSelect");
if (langSelect) {
langSelect.addEventListener("change", () => {
renderPage();
});
}
}